export const SPELL_LISTS: SpellListCatalogEntry[] = SPELL_LISTS_RAW;

const unmappedBaseListIds = SPELL_LISTS.filter((list) => list.type === "Base" && (list.baseProfessions?.length ?? 0) === 0).map((list) => list.id);
if (unmappedBaseListIds.length > 0) {
  throw new Error(`Missing base profession mapping for Base spell list IDs: ${unmappedBaseListIds.join(", ")}`);
}

export function spellListsByRealmAndType(realm: SpellListCatalogEntry["realm"], type: SpellListCatalogEntry["type"]) {
  return SPELL_LISTS.filter((list) => list.realm === realm && list.type === type);
}

export function baseSpellListsByProfession(professionName: string) {
  return SPELL_LISTS.filter((list) => list.type === "Base" && list.baseProfessions?.includes(professionName));
}
